var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"어…….","JPN":"ど……","ENG":"Uh...","TWN":"怎……"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"어째서……?","JPN":"どうして……","ENG":"But why...?","TWN":"怎麼會……？"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"어째서 당신이 여기에……?","JPN":"どうしてあなたがここに……？","ENG":"W-why are you here...?","TWN":"為什麼你會……？"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JIA_ALPHA_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아가씨?","JPN":"お嬢様？","ENG":"Miss Jia?","TWN":"小姐？"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"안 됩니다, 아가씨! 총을 거두세요! 아가씨의 숙부님이십니다!","JPN":"いけません、お嬢様！　銃を下ろしてください！　お嬢様の叔父様なのですよ！","ENG":"No, Jia! You can’t! He’s your uncle!","TWN":"不可以，小姐！把槍放下！再怎麼說他也是你的叔叔！"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"큭큭...... 내가 선수를 빼앗겼군, 이 실장......","JPN":"ククッ……私が先手を取られたようだな、シノザキ室長……","ENG":"Keke... Looks like I was too slow, Chief Lee...","TWN":"唔……竟然被你先下手為強，李室長……"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"저 빌어먹을 괴물은…….","JPN":"あのクソ化け物は……","ENG":"That monster is...","TWN":"該死的怪物……"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DRIVER_NPC_ALPHA_NULL","text":{"KOREA":"으아아아악!","JPN":"うわあああっ！","ENG":"Aaaagh!!","TWN":"啊啊啊啊！"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DRIVER_NPC_ALPHA_NULL","text":{"KOREA":"부, 부회장님이! 부회장님이 죽었어!","JPN":"ふ、副会長が！　副会長が死んでしまった！","ENG":"Y-you...! You killed the Vice Chairman!","TWN":"副…副會長！副會長死了！"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아가씨……. 대체 왜……?","JPN":"お嬢様……いったいどうして……？","ENG":"Jia... W-why...?","TWN":"小姐……你為什麼……？"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아하, 이진 언니는 이노베이션에 오기 전에는 숙부님의 비서셨죠?","JPN":"残念ですね。そういえば、ホノカさんはイノベーションに来る前、叔父様の秘書をされていましたよね？","ENG":"That’s right! You were Uncle’s secretary before joining Innovation.","TWN":"哦～李珍姐之前是叔叔的秘書對吧？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……네.","JPN":"……はい。","ENG":"Yes...","TWN":"……是的，"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":" 이젠 아니지만요.","JPN":"今はもう違いますが……","ENG":"But not anymore.","TWN":"但現在不是。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그렇구나. 오랫동안 못 보셨으니까 비서 시절 생각이 많이 나시겠네요.","JPN":"そうでしたね。叔父様とは久しぶりに会いますし、\\n色々と秘書時代のことを思い出すひと時になりそうですね。","ENG":"I see. Then I’m sure you were delighted to see him again.","TWN":"那你們這麼久不見，應該會想起很多以前的事吧～"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그 때 그 질문…… 설마 처음부터 부회장님과 제 관계를 알고서…….","JPN":"あの時のあの質問……まさか最初から副会長と私の関係を知ってて……","ENG":"That night... You knew from the start about my relationship with him and...","TWN":"難道……你打從一開始就知道我和副會長的關係才……"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DRIVER_NPC_ALPHA_NULL","text":{"KOREA":"쏘, 쏘지 마!! 누가 좀 살려 줘!","JPN":"う、撃つな！！　誰か助けて！","ENG":"D-don’t shoot!! Somebody!! Help me!!","TWN":"別…別開槍！誰快來救命啊！"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아가씨는 제가 막겠습니다! 어서 도망치세요!!","JPN":"お嬢様は私が止めます！　早く逃げてください！！","ENG":"I’ll stop her! Run!","TWN":"小姐就交給我，你快逃！！"},"stage":{"bg":"DONGDAEMUN_DARK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L35_1","type":"narration","speaker":null,"text":{"KOREA":"……운전수는 어떻게든 지켰지만, 혼자 상대하기엔 역부족이었어요.","JPN":"……運転手はなんとか守り抜きましたが、\\n一人で太刀打ちできる相手ではありませんでした。","ENG":"The driver got away safely, but I wasn’t strong enough to stop it from happening.","TWN":"……雖然司機順利逃走，但我實在不是小姐的對手，"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"narration","speaker":null,"text":{"KOREA":"저 역시 현장에서 도망치는 게 고작이었죠.","JPN":"私も現場から逃げるのがやっとでしたから。","ENG":"All I could do was run away.","TWN":"因此最後也只能選擇逃離現場。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"사실대로 말씀해 주세요, 아가씨.","JPN":"事実を教えてください、お嬢様。","ENG":"Tell us the truth, Miss Jia.","TWN":"小姐，請你老實跟我說，"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"저와 싸웠던 <color=#ffd34c>그건</color>…… 정말 아가씨였나요?","JPN":"私と戦った<color=#ffd34c>あれ</color>は……本当にお嬢様だったのですか？","ENG":"Was <color=#ffd34c>that</color> really you, who I was fighting?","TWN":"昨天攻擊我的<color=#ffd34c>那個人</color>……真的是你嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"우리는 당시 현장을 먼저 벗어났다는 운전수의 진술을 확보해서 왔던 거야.","JPN":"私たちは、当時現場を先に離れた運転手の証言でここに来たの。","ENG":"We first got the driver’s testimony.","TWN":"我們是聽完當時逃跑的司機說詞後才過來的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"운전수의 진술도 저 여자가 한 얘기와 똑같아.","JPN":"運転手の証言もあの女の話と一致してる。","ENG":"He said the same thing as she did.","TWN":"而司機的說詞和剛那女人說的不謀而合。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"새롬이 얘기했던 대로 리더는 알리바이가 있어요.","JPN":"アサネの言うとおり、リーダーにはアリバイがあります。","ENG":"But as Saerom said, Leader also has an alibi.","TWN":"根據芷倫的說法，老大是有不在場證明的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"오히려 그 두 사람이 부회장을 살해하고 진술을 꾸몄을 가능성도 있을 텐데요.","JPN":"むしろ、二人が副会長を殺害して口裏を合わせた可能性もあるのでは？","ENG":"To me, it just sounds like the two of them murdered the Vice Chairman and are trying to cover it up.","TWN":"應該也有可能是司機和室長串謀殺害副會長，再賴給老大吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"초원 양! 제가 어떻게 그럴 거라고……!","JPN":"ナオさん！　私を疑うなんて……！","ENG":"Chowon! How could you even think that I...?!","TWN":"初源！我怎麼可能做那種事……！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"흥, 얼버무릴 생각 하지 마. 안경.","JPN":"フン、しらを切るのやめてよね、メガネ。","ENG":"Hmph! Don’t play dumb with me, Glasses.","TWN":"哼，眼鏡妹，你別想混淆視聽！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"감찰과 선배들에게 다 들었거든. 신지아 대표의 <color=#ffd34c>능력</color>에 대해서 말이야.","JPN":"監察課の先輩たちに全部聞いたんだよ。ヒメノ代表の<color=#ffd34c>能力</color>についてね。","ENG":"I heard about everything from the agents over at Investigations. About Shin Jia’s <color=#ffd34c>abilities</color> too.","TWN":"監察科的前輩有跟我說過沈佳代表<color=#ffd34c>能力</color>。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"……<color=#ffd34c>질량 부여</color>말인가요?","JPN":"……<color=#ffd34c>質量付与</color>のことですか？","ENG":"You mean <color=#ffd34c>Matter Manifestation</color>?","TWN":"……你是說<color=#ffd34c>賦予質量</color>嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"그래! 증강 현실 장치로 구현된 홀로그램에 질량을 부여해서 진짜처럼 만든다며?","JPN":"そのとおり！　拡張現実装置で具現化されたホログラムに、\\n質量を付与して本物同然の状態にするんだって？","ENG":"Yeah! I heard she can make things appear in real life with that augmented reality device!","TWN":"沒錯！聽說透過擴增實境裝置產生的全息圖，只要賦予質量就可以跟真的一樣？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"}}}},{"id":"L3_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"그렇게 만든 분신들로 그라운드 원을 휘젓고 다녔다지?","JPN":"そうやってつくった分身たちでグラウンド・ワンをかき回してたそうだし。","ENG":"You cloned yourself and wrecked havoc on Ground One, right?","TWN":"你是利用分身替你在G1作亂吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"그러니까 분신으로 범행을 저지른 후에 지워 버리기만 하면…….","JPN":"分身で犯行に及んだ後、分身を消してしまえば……","ENG":"After your clone does the dirty work, all you have to do is erase it and...","TWN":"分身犯下罪行後，你再把分身處理掉，這樣就是……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"짜잔! 완전범죄 성립!","JPN":"ババン！　完全犯罪、成立！","ENG":"Kachow! The perfect crime!","TWN":"鏘鏘！完美犯罪！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"어? 완전 범죄…… 아니야?","JPN":"あれ？　完全犯罪……じゃないの？","ENG":"Huh? Isn’t it... the perfect crime?","TWN":"嗯？不是完美犯罪……嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"이, 이상하다. 파사의 목소리가 알려 준 대로 말했는데…….","JPN":"へ、変だな。破邪の声が教えてくれたとおりに言ったのに……","ENG":"Th-that’s weird. I said it exactly how the Voice of Evil Eradication told me...","TWN":"奇怪，是破邪之聲告訴我的……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저, 라파엘라 씨. 그것뿐이라면 다른 분들이 납득하기가 어려울 것 같아요.","JPN":"あの、ラファエラさん。それだけだと皆さんを納得させるのは難しいと思います。","ENG":"Um, Raphaela? I don’t think that’s enough to convince everyone.","TWN":"拉菲樂，如果只是這個原因，大家可能無法接受這樣的說法。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"겉모습을 바꾸거나, 오감을 속이는 정도라면 제 능력이 아니더라도 방법은 많으니까요.","JPN":"外見を変えたり感覚を騙す程度でしたら、私の能力でなくても\\n方法はたくさんありますからね。","ENG":"There are numerous ways one can deceive others even without my ability.","TWN":"畢竟偽裝或是障眼法這種事，就算沒有我的能力，也有其他許多方法能辦得到。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"맞아요. 실장님과 운전수가 오해했을 가능성은 충분합니다.","JPN":"そうです。室長と運転手が誤認した可能性は十分あります。","ENG":"She’s right. There's also the chance that Chief and the driver are both mistaken.","TWN":"沒錯，很有可能是室長和司機認錯人。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"초원 양, 만약 그랬다면 제가 먼저 감찰과로 찾아가서 알렸을 거예요.","JPN":"ナオさん、もしそうだったなら、私が先に監察課に行って知らせたはずです。","ENG":"Chowon, if that was the case, I would’ve confronted Investigations myself.","TWN":"初源，若是如此，那我第一個就會先去告訴監察科。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"분위기는 달랐지만…… <color=#ffd34c>그것</color>은 아가씨와 똑같은 움직임을 보였어요.","JPN":"雰囲気は違いましたが……<color=#ffd34c>あれ</color>はお嬢様と同じ動きをしていました。","ENG":"Her aura was different... but <color=#ffd34c>that</color> moved the same way as Miss Jia.","TWN":"雖然氛圍不太一樣……但<color=#ffd34c>那個人</color>的動作和小姐如出一轍。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"초원 양도 베테랑이니 잘 아시겠죠. 아가씨의 움직임은 흉내낼 수 있는 게 아니라는 걸.","JPN":"ナオさんもベテランですからよくご存知のはずです。\\nお嬢様の動きは他人が真似できるようなものではありません。","ENG":"Chowon, you may also know, but Jia’s movements aren’t easy to copy.","TWN":"初源你也知道，小姐的動作是模仿不來的！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"좋아요. 지금까지 나온 말들이 모두 진실이라고 치죠.","JPN":"まあいいでしょう。これまでの話がすべて事実だとしましょう。","ENG":"Fine. Let’s assume that what was said here is all true.","TWN":"好，那就當作你剛說的都是真的，"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"하지만 리더가 실장님과 부회장을 노릴 동기가 없다는 건 본인이 가장 잘 알지 않나요?","JPN":"しかし、リーダーに室長と副会長を狙う動機が無いのは、あなたが一番よく知っているのでは？","ENG":"But you must also know that Leader has no motive to go after you or the Vice Chairman.","TWN":"但你自己應該也很清楚，老大並沒有殺害室長和副會長的動機吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"That’s...","TWN":"這個……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"흐음……. 뭔가 잊은 것 같군, 이 실장.","JPN":"ふむ……何か忘れていないか、シノザキ室長。","ENG":"Hmm... I think you’re forgetting something, Chief Lee.","TWN":"嗯……李室長，你是不是忘了？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"나는 기회가 생겼을 때 그 괴물을 없애라고 자네를 이노베이션에 심어 둔 걸세.","JPN":"私はあの化け物を消す機会を窺うために、\\n君をイノベーションに潜入させたつもりだ。","ENG":"I put you in Innovation so that you can get rid of her when the opportunity arises.","TWN":"當初我派你去改革時，是要你一有機會就把那個怪物除掉。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"내가 언제 자네에게 베이비시터 노릇까지 하라고 했던가?","JPN":"君に子守りの役まで頼んだおぼえは無いが？","ENG":"I don’t remember putting you on babysitting duties now, did I?","TWN":"我是叫你去當保母的嗎？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……말씀드릴 수 없어요. 미안합니다, 초원 양.","JPN":"……それについては言えません。ごめんなさい、ナオさん。","ENG":"...I’m sorry, but I can’t tell you anymore at this point, Chowon.","TWN":"……這一點恕我無可奉告，抱歉，初源。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"오해를 풀려면 시간이 더 필요하겠네요, 리더.","JPN":"誤解を解くには少し時間が必要ですね、リーダー。","ENG":"Looks like we need more time to get this straightened out, Leader.","TWN":"看來要解開誤會還需要一些時間，老大。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"초원 씨……?","JPN":"ナオさん……？","ENG":"Chowon...?","TWN":"初源……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"아시다시피, 이 <color=#ffd34c>스마트 글래스</color>는 전황 분석에 필요한 시청각 자료 수집용으로 유용합니다.","JPN":"ご存じのとおり、この<color=#ffd34c>スマートグラス</color>は、戦況分析に必要な視聴覚資料を収集できます。","ENG":"As you may be aware, these <color=#ffd34c>Smart Glasses</color> are useful for gathering audiovisual data required for battle analysis.","TWN":"老大，你也知道這個<color=#ffd34c>智能眼鏡</color>，對於收集視聽覺資料來分析戰況很有用。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"……지금은 저보다 리더에게 더 필요한 물건 같네요. 가져가세요.","JPN":"……今は私よりもリーダーに必要だと思います。どうぞお持ちください。","ENG":"Right now, you need it more than me, Leader. Take it.","TWN":"……現在老大似乎比我還需要，你拿去吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네? 그러면 초원 씨는 어떻게 하시려고……?","JPN":"えっ？　それではナオさんはどうするつもりで……？","ENG":"Huh? But what about you...?","TWN":"什麼？那你怎麼辦……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"둘이서 뭘 쑥덕거리는 거야?","JPN":"二人で何をコソコソしてるの？","ENG":"What are you two whispering about?","TWN":"你們那個在那邊嘀嘀咕咕什麼？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"앗?! 설마 내 앞에서 사악한 음모를!?","JPN":"あっ！？　まさか私の前で邪悪な陰謀を！？","ENG":"Huh?! Are you two conspiring something evil in front of me?!","TWN":"你們該不會？！是在我面前計畫什麼邪惡的事嗎？！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"땡. 정답 공개합니다.","JPN":"ブー。　正解は……","ENG":"Wrong! The correct answer is...","TWN":"噹！答錯！公布正確答案。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"부, 부비트랩?! 언제 이런 짓을!","JPN":"ブ、ブービートラップ！？　いつの間にこんなものを！","ENG":"A b-boobytrap?! When did you...?!","TWN":"詭雷？！你是什麼時候！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"학교 끝나고 들를 때마다 설치해 뒀죠. ","JPN":"学校帰りに寄るたびに設置しておきました。","ENG":"I always set them up after I get back from school.","TWN":"我每次放學回來的路上都會設置。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"요즘 학생들 사이에선 넷튜브 다음으로 인기 있는 취미활동입니다.","JPN":"最近学生の間でネットチューブの次に流行ってる趣味活動です。","ENG":"It’s a hobby popular among students besides NetTube.","TWN":"這是最近的學生們除了看直播之外的樂趣。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"뭐야, 그게! 무서워!!","JPN":"なんだよそれ！　怖い！！","ENG":"What the heck?!","TWN":"這算什麼樂趣！可怕！！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"제가 이런 말을 하게 될 줄은 몰랐지만, 먼저 가세요. 리더.","JPN":"こんなことを言う日が来るとは思いませんでしたが、先に行ってください、リーダー。","ENG":"I never thought I would say these words but, you go ahead, Leader.","TWN":"沒想到有一天我會說這句話，老大，你先逃吧！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"초원 씨, 하지만…….","JPN":"ナオさん、でも……","ENG":"But Chowon...","TWN":"初源，可是……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"제 신변 안전에 대해선 걱정 마세요. 방임 교육 속에서도 바르게 자란 이력이 있으니까요.","JPN":"私の身の安全は心配しないでください。\\n放任主義の中で、強く正しく育ってきましたから。","ENG":"Don’t worry about me. I’ve managed to come this far with a neglected past, right?","TWN":"不用擔心我的安危，我自己可以保護好自己的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"그보다 이건 누군가 리더를 엮으려고 파 둔 함정이에요. ","JPN":"それより、これは誰かがリーダーを陥れるために仕組んだ罠です。","ENG":"Right now, someone’s trying to set you up, Leader.","TWN":"這很明顯是誰要陷害老大而設下的陷阱，"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"증언만으로 감찰과가 사무실에 공격을 퍼붓지는 않아요. 마음 독하게 먹으세요.","JPN":"証言だけで監察課がオフィスに攻撃を仕掛けることはありません。\\nどうか心を強く持ってください。","ENG":"Investigations doesn’t just raid offices on a witness statement. We need to get to the bottom of this.","TWN":"監察科是不會單憑供詞就攻擊辦公室的，你千萬不能心軟。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"꼭, 진상을 밝힐 수 있길 응원하겠습니다.","JPN":"必ず真相を解明できるようにサポートします。","ENG":"I’ll be rooting for you to unveil the truth.","TWN":"我會幫助你查明真相的！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"하아. 하아, 하아…….","JPN":"はあ、はあ、はあ……","ENG":"*Huff*... *Huff*... *Huff*...","TWN":"呼呼呼……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"결국……. 또 혼자가 돼 버렸어…….","JPN":"結局……また一人になった……","ENG":"I’m... all alone again...","TWN":"結果……又變成我自己一個人……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"할아버님은 이럴 때…….","JPN":"お祖父様はこんな時……","ENG":"Grandfather, if only...","TWN":"這種時候……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이럴 때, 어떻게 해야 좋은지 말씀해 주셨으면 좋았을 텐데…….","JPN":"こんな時、どうすべきか教えてくださればよかったのに……","ENG":"you could guide me during times like this...","TWN":"真希望爺爺能告訴我該怎麼做……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_QM","text":{"KOREA":"어라? 거기 너는 지아 아니냐?","JPN":"あれ？　そこの君はユイちゃんじゃない？","ENG":"Huh? Aren’t you Jia?","TWN":"嗯？你不是沈佳嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"당신은……?","JPN":"あなたは……？","ENG":"And you are...?","TWN":"你是……？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그래, 세실리아다. 어제는 방해꾼들 탓에 얘기도 제대로 못했지. ","JPN":"ふふ、セシリアよ。昨日は邪魔が入って、ろくに話もできなかったわね。","ENG":"It’s me, Cecilia. Our conversation was cut short yesterday because of interruptions.","TWN":"我是賽希莉亞，昨天因為那些礙事的傢伙，害我沒辦法好好和你說話。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그런데 여기는 혼자 어쩐 일인고?","JPN":"ところで、一人でここに来るなんて何の用かしら？","ENG":"But, what are you doing out here all alone?","TWN":"不過你怎麼會一個人在這裡？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};